import { AdvancedSearchEndpoint } from '../../query-builder.types'
import { FormlyFieldConfig } from '@ngx-formly/core'
import { getSelectOptions } from './get-select-options'
import { getFieldOptions } from './get-field-options'
import { BooleanOperator } from '@generated/civic.apollo'
import { AbstractControl } from '@angular/forms'

const filterCompleteValidator = {
  expression: (c: AbstractControl): boolean => {
    const value = c.value
    if (
      !value ||
      typeof value !== 'object' ||
      Object.keys(value).length === 0
    ) {
      return false
    }
    return true
  },
  message: 'Select an attribute or remove this filter.',
}

export function getQueryFieldConfig(
  key: 'query' | string = 'query',
  endpoint: AdvancedSearchEndpoint,
  title?: string
): FormlyFieldConfig[] {
  // generate root query field config
  if (key === 'query') {
    return [
      {
        // NOTE: field type added in entity config with config helper function
        key: `${key}`,
        wrappers: [`query-builder-card`],
        props: {
          formCardOptions: {
            title: title,
            size: 'small',
            searchEndpoint: endpoint,
          },
        },
        fieldGroup: [
          {
            key: 'booleanOperator',
            type: 'base-radio',
            wrappers: [],
            props: {
              required: true,
              type: 'button',
              options: getSelectOptions('BooleanOperator'),
            },
          },
          {
            key: 'subFilters',
            type: 'query-subfilters',
            wrappers: [],
            props: {
              filterEndpoint: endpoint,
              isRootFilter: true,
            },
            fieldArray: (field) => {
              return {
                type: 'query-filter',
                resetOnHide: true,
                validators: {
                  filterComplete: filterCompleteValidator,
                },
                props: {
                  options: getFieldOptions(
                    field.props!.filterEndpoint,
                    true
                  ).map((opt) => ({
                    label: opt.props?.label,
                    value: opt.key,
                  })),
                },
                fieldGroup: getFieldOptions(
                  field.props!.filterEndpoint,
                  field.props!.isRootFilter
                ),
              }
            },
          },
        ],
      },
      {
        key: 'createPermalink',
        defaultValue: true,
      },
    ]
  } else {
    // generate subfilter field config
    return [
      {
        // NOTE: field type added in entity config with config helper function
        key: `${key}`,
        wrappers: ['query-subfilters-card'],
        props: {
          label: `${title}`,
          formCardOptions: { title: title, size: 'small' },
        },
        fieldGroup: [
          {
            key: 'booleanOperator',
            type: 'base-radio',
            defaultValue: 'AND',
            wrappers: [],
            props: {
              required: true,
              size: 'small',
              type: 'button',
              options: getSelectOptions('BooleanOperator'),
            },
          },
          {
            key: 'subFilters',
            type: 'query-subfilters',
            wrappers: [],
            props: {
              filterEndpoint: endpoint,
              isRootFilter: false,
            },
            fieldArray: (field) => {
              return {
                type: 'query-filter',
                resetOnHide: true,
                validators: {
                  filterComplete: filterCompleteValidator,
                },
                props: {
                  isRootFilter: false,
                  options: getFieldOptions(
                    field.props!.filterEndpoint,
                    true
                  ).map((opt) => ({
                    label: opt.props?.label,
                    value: opt.key,
                  })),
                },
                fieldGroup: getFieldOptions(
                  field.props!.filterEndpoint,
                  field.props!.isRootFilter
                ),
              }
            },
          },
        ],
      },
    ]
  }
}
